15	                part.parse::<usize>()
16	                    .map_err(|e| format!("invalid core id {part:?}: {e}"))?,
17	            ),
18	            Some((lo, hi)) => {
19	                let lo = lo
20	                    .trim()
21	                    .parse::<usize>()
22	                    .map_err(|e| format!("invalid range start {lo:?}: {e}"))?;
23	                let hi = hi
24	                    .trim()
25	                    .parse::<usize>()
26	                    .map_err(|e| format!("invalid range end {hi:?}: {e}"))?;
27	                if hi < lo {
28	                    return Err(format!("range {lo}-{hi} is empty"));
29	                }
30	                out.extend(lo..=hi);
31	            }
32	        }
33	    }
34	    Ok(out)
35	}
