42	    eprintln!("{prompt}: cid={cid}");
43	}
44	
45	/// Pin the current thread to `logical_cpu`. No-op if `None`.
46	///
47	/// Constructs a `CoreId` directly rather than querying
48	/// `get_core_ids()`, which only returns cores in the caller's
49	/// current affinity mask — after the first pin that mask is
50	/// narrowed and subsequent lookups for other cores would fail.
51	pub fn pin_current(logical_cpu: Option<usize>) {
52	    let Some(target) = logical_cpu else { return };
53	    core_affinity::set_for_current(core_affinity::CoreId { id: target });
54	}
55	
56	/// Read the current thread's CPU affinity mask, or `None` if the
57	/// syscall fails (very unusual on Linux).
58	pub fn current_affinity() -> Option<libc::cpu_set_t> {
59	    let mut set: libc::cpu_set_t = unsafe { std::mem::zeroed() };
60	    let ret = unsafe { libc::sched_getaffinity(0, size_of::<libc::cpu_set_t>(), &mut set) };
61	    (ret == 0).then_some(set)
62	}
