65	/// later. Logs the captured mask at `info` level. Returns `None` on
66	/// syscall failure (very unusual on Linux).
67	pub fn save_affinity() -> Option<libc::cpu_set_t> {
68	    match current_affinity() {
69	        Some(set) => {
70	            log::info!("save_affinity: mask={}", affinity_summary(&set));
71	            Some(set)
72	        }
73	        None => {
74	            log::warn!("save_affinity: sched_getaffinity failed");
75	            None
76	        }
77	    }
78	}
79	
80	/// Restore a previously-saved affinity mask. Used after calibration
81	/// to widen the mask back to what we started with (typically "all
82	/// CPUs the process was launched with", preserving any outer
83	/// `taskset` restrictions). Logs the restored mask at `info` level.
84	pub fn restore_affinity(set: &libc::cpu_set_t) {
85	    let ret = unsafe { libc::sched_setaffinity(0, size_of::<libc::cpu_set_t>(), set) };
86	    if ret == 0 {
87	        log::info!("restore_affinity: mask={}", affinity_summary(set));
88	    } else {
