93	/// Format a CPU set as a compact range list with a count suffix,
94	/// e.g. `"0-11,13-15 (15 cpus)"` or `"5 (1 cpu)"`.
95	pub fn affinity_summary(set: &libc::cpu_set_t) -> String {
96	    let cpus: Vec<usize> = (0..libc::CPU_SETSIZE as usize)
97	        .filter(|&i| unsafe { libc::CPU_ISSET(i, set) })
98	        .collect();
99	    if cpus.is_empty() {
100	        return "<empty>".to_string();
101	    }
102	    let mut ranges: Vec<String> = Vec::new();
103	    let mut start = cpus[0];
104	    let mut prev = cpus[0];
105	    for &c in &cpus[1..] {
106	        if c == prev + 1 {
107	            prev = c;
108	        } else {
109	            ranges.push(if start == prev {
110	                start.to_string()
111	            } else {
112	                format!("{start}-{prev}")
113	            });
114	            start = c;
115	            prev = c;
116	        }
117	    }
118	    ranges.push(if start == prev {
119	        start.to_string()
120	    } else {
121	        format!("{start}-{prev}")
122	    });
123	    format!(
124	        "{} ({} cpu{})",
125	        ranges.join(","),
126	        cpus.len(),
127	        if cpus.len() == 1 { "" } else { "s" }
128	    )
129	}
