138	    format!(
139	        "{cores:?} ({} slot{}, {} unique CPU{})",
140	        cores.len(),
141	        if cores.len() == 1 { "" } else { "s" },
142	        unique.len(),
143	        if unique.len() == 1 { "" } else { "s" },
144	    )
145	}
